// ====================================================================
// EDIT TOPIC + DESCRIPTION to test different infographics.
// The AI prompt engineer will choose the best style and write the prompt.
// ====================================================================

const TOPIC = 'Why open-source AI is becoming the default stack for builders';

const DESCRIPTION = `Talk about how teams can combine Hugging Face Transformers for pretrained models, Ollama for local model runs, and vLLM for scalable serving. This is a strong â€œbuilder mindsetâ€ post because it shows the shift from â€œusing AIâ€ to â€œshipping AI systems`;

return [{ json: { topic: TOPIC, description: DESCRIPTION } }];

// Combines topic + description + Firecrawl web research into
// the image_prompt_request text that the AI prompt engineer agent reads.

const inputs = $('set_inputs').first().json;
const topic = inputs.topic;
const description = inputs.description;

// Count steps/elements to help agent pick style
const stepCount = (description.match(/\b(step|stage|phase|layer|part)\s+\d|\d+\s+(step|stage|phase|layer|part)|\bfirst\b|\bsecond\b|\bthird\b|\bfourth\b|\bfifth\b/gi) || []).length;
const hasComparison = /\bvs\b|\bversus\b|\bcompare|before.+after|old.+new|traditional.+modern/i.test(description);
const hasStats = /\b\d+[\.,]\d+|\b\d+[%x]\b|\bmillion\b|\bbillion\b|\bfaster\b|\bmore\b/i.test(description);
const namedTools = (description.match(/\b[A-Z][a-zA-Z]+(?:AI|ML|LLM|DB|GPT|API)?\b/g) || [])
  .filter(w => w.length > 3).slice(0, 8);

// Collect web search snippets
let researchSnippets = '';
try {
  const lines = $input.all()
    .filter(r => r.json && r.json.title)
    .slice(0, 8)
    .map(r => `- ${r.json.title}: ${(r.json.description || '').substring(0, 150)}`);
  if (lines.length > 0) researchSnippets = lines.join('\n');
} catch(e) {}

// Hint to guide style selection
let styleHint = '';
if (hasComparison) styleHint = 'Content appears to compare two things â€” consider COMPARISON style [B].';
else if (hasStats) styleHint = 'Content has statistics/benchmarks â€” consider BOLD STAT POSTER style [F].';
else if (stepCount === 0 && namedTools.length > 4) styleHint = 'Multiple tools in an ecosystem â€” consider HUB-AND-SPOKE style [C].';
else if (stepCount >= 2 && stepCount <= 5) styleHint = `Content has ~${stepCount} steps â€” ISOMETRIC style [A] may fit, but verify it is truly sequential.`;
else styleHint = 'No clear pipeline structure â€” consider EDITORIAL SCENE [E] or HUB-AND-SPOKE [C].';

const request = `TOPIC: ${topic}

DESCRIPTION:
${description}

NAMED TOOLS/COMPANIES DETECTED: ${namedTools.join(', ') || '(none detected â€” scan description yourself)'}
CONTENT STRUCTURE HINT: ${styleHint}

WEB RESEARCH (use for visual accuracy â€” real tool names, logos, architectures):
${researchSnippets || '(no research available)'}

---
TASK: Write ONE detailed Gemini image generation prompt for this topic.
Follow your system message â€” analyse content structure first, choose the best style [Aâ€“F], then write a rich scene description.
The prompt must be at least 200 words and describe every visual element specifically.
The Prompt should generate the professional Image standards of Linkedin.

Output ONLY inside these markers:

===IMAGE_PROMPT_V1_START===
[your prompt here]
===IMAGE_PROMPT_V1_END===`;

return [{ json: { image_prompt_request: request, topic, description } }];

// Parse ===IMAGE_PROMPT_V1_START=== ... ===IMAGE_PROMPT_V1_END=== from agent output.
// Falls back to full output if markers are missing.

const agentOutput = $input.first().json.output || $input.first().json.text || '';

const v1Match = agentOutput.match(/===IMAGE_PROMPT_V1_START===([\s\S]*?)===IMAGE_PROMPT_V1_END===/);

let prompt;
if (v1Match) {
  prompt = v1Match[1].trim();
  console.log('[extract_prompt] Extracted prompt, length:', prompt.length);
} else {
  prompt = agentOutput.trim();
  console.log('[extract_prompt] No markers â€” using full output, length:', prompt.length);
}

if (!prompt || prompt.length < 50) {
  throw new Error('Prompt too short or empty. Agent output: ' + agentOutput.substring(0, 500));
}

return [{ json: { prompt } }];

// Decode Gemini image output â€” handles both native binary and HTTP API fallback.
const ts = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
const label = ($('set_inputs').first().json.topic || 'test')
  .toLowerCase().replace(/[^a-z0-9]+/g, '_').substring(0, 30);

const nativeBinary = $input.first().binary?.data;
let imageBuffer, mimeType;

if (nativeBinary) {
  mimeType = nativeBinary.mimeType || 'image/jpeg';
  imageBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
} else {
  const response = $input.first().json;
  const parts = response.candidates?.[0]?.content?.parts || [];
  const imgPart = parts.find(p => p.inlineData && (p.inlineData.mimeType || '').startsWith('image/'));
  if (!imgPart) {
    const txt = parts.filter(p => p.text).map(p => p.text).join('\n');
    throw new Error('No image in response. Model text: ' + txt.substring(0, 500));
  }
  mimeType = imgPart.inlineData.mimeType || 'image/jpeg';
  imageBuffer = Buffer.from(imgPart.inlineData.data, 'base64');
}

const ext = mimeType.includes('jpeg') ? 'jpg' : 'png';
const filename = label + '_' + ts + '.' + ext;
const imageBinary = await this.helpers.prepareBinaryData(imageBuffer, filename, mimeType);

return [{ json: { filename, mimeType, size_bytes: imageBuffer.length }, binary: { image: imageBinary } }];
